//! Parser - AST builder
//! Generated by Python

use super::ast::*;
use super::lexer::*;

pub struct Parser {
    tokens: Vec<Token>,
    pos: usize,
}

impl Parser {
    pub fn new(tokens: Vec<Token>) -> Self { Self { tokens, pos: 0 } }

    pub fn parse(&mut self) -> Result<Program, String> {
        let mut body = Vec::new();
        while !self.is_eof() { body.push(self.parse_stmt()?); }
        Ok(Program { body })
    }

    fn parse_stmt(&mut self) -> Result<Stmt, String> {
        if self.is_eof() { return Err("Unexpected end of input".to_string()); }
        match self.peek().kind {
            TokenKind::KwLet | TokenKind::KwConst | TokenKind::KwVar => self.parse_var_decl(),
            TokenKind::KwFunction => self.parse_function_decl(),
            TokenKind::KwIf => self.parse_if(),
            TokenKind::KwWhile => self.parse_while(),
            TokenKind::KwFor => self.parse_for(),
            TokenKind::KwReturn => self.parse_return(),
            TokenKind::KwBreak => { self.advance(); Ok(Stmt::Break) }
            TokenKind::KwContinue => { self.advance(); Ok(Stmt::Continue) }
            TokenKind::KwTry => self.parse_try(),
            TokenKind::KwThrow => self.parse_throw(),
            _ => {
                let expr = self.parse_expr()?;
                // Consume optional semicolon
                if !self.is_eof() && matches!(self.peek().kind, TokenKind::PunctSemi) {
                    self.advance();
                }
                Ok(Stmt::Expr(expr))
            }
        }
    }

    fn parse_var_decl(&mut self) -> Result<Stmt, String> {
        let is_const = matches!(self.peek().kind, TokenKind::KwConst);
        self.advance();
        let name = self.expect_identifier()?;
        let value = if !self.is_eof() && matches!(self.peek().kind, TokenKind::OpAssign) {
            self.advance();
            Some(self.parse_expr()?)
        } else { None };
        // Consume optional semicolon
        if !self.is_eof() && matches!(self.peek().kind, TokenKind::PunctSemi) {
            self.advance();
        }
        Ok(Stmt::VarDecl { name, value, is_const })
    }

    fn parse_function_decl(&mut self) -> Result<Stmt, String> {
        self.advance();
        let name = self.expect_identifier()?;
        let params = self.parse_params()?;
        let body_stmts = self.parse_block_body()?;
        // Consume optional semicolon
        if !self.is_eof() && matches!(self.peek().kind, TokenKind::PunctSemi) {
            self.advance();
        }
        Ok(Stmt::FunctionDecl { name, params, body: body_stmts })
    }

    fn parse_params(&mut self) -> Result<Vec<String>, String> {
        if self.is_eof() || !matches!(self.peek().kind, TokenKind::PunctLParen) {
            return Err("Expected (".to_string());
        }
        self.advance();
        let mut params = Vec::new();
        while !self.is_eof() && !matches!(self.peek().kind, TokenKind::PunctRParen) {
            if matches!(self.peek().kind, TokenKind::PunctSpread) { self.advance(); }
            params.push(self.expect_identifier()?);
            if matches!(self.peek().kind, TokenKind::PunctComma) { self.advance(); }
        }
        self.advance();
        Ok(params)
    }

    fn parse_block_body(&mut self) -> Result<Vec<Stmt>, String> {
        if self.is_eof() || !matches!(self.peek().kind, TokenKind::PunctLBrace) {
            return Err("Expected {".to_string());
        }
        self.advance();
        let mut stmts = Vec::new();
        while !self.is_eof() && !matches!(self.peek().kind, TokenKind::PunctRBrace) {
            stmts.push(self.parse_stmt()?);
        }
        if !self.is_eof() { self.advance(); }
        Ok(stmts)
    }

    fn parse_if(&mut self) -> Result<Stmt, String> {
        self.advance();
        let condition = self.parse_expr()?;
        let then_branch = self.parse_block_body()?;
        let else_branch = if !self.is_eof() && matches!(self.peek().kind, TokenKind::KwElse) {
            self.advance();
            Some(self.parse_block_body()?)
        } else { None };
        Ok(Stmt::If { condition, then_branch, else_branch })
    }

    fn parse_while(&mut self) -> Result<Stmt, String> {
        self.advance();
        let condition = self.parse_expr()?;
        let body = self.parse_block_body()?;
        Ok(Stmt::While { condition, body })
    }

    fn parse_for(&mut self) -> Result<Stmt, String> {
        self.advance();
        if self.is_eof() || !matches!(self.peek().kind, TokenKind::PunctLParen) { return Err("Expected (".to_string()); }
        self.advance();
        let init = if self.is_eof() {
            return Err("Unexpected EOF in for".to_string());
        } else if matches!(self.peek().kind, TokenKind::PunctSemi) {
            None
        } else if matches!(self.peek().kind, TokenKind::KwLet | TokenKind::KwConst | TokenKind::KwVar) {
            Some(Box::new(self.parse_var_decl()?))
        } else {
            let e = self.parse_expr()?;
            Some(Box::new(Stmt::Expr(e)))
        };
        if self.is_eof() || !matches!(self.peek().kind, TokenKind::PunctSemi) { return Err("Expected ;".to_string()); }
        self.advance();
        let condition = if self.is_eof() {
            return Err("Unexpected EOF in for".to_string());
        } else if matches!(self.peek().kind, TokenKind::PunctSemi) {
            None
        } else { Some(self.parse_expr()?) };
        if self.is_eof() || !matches!(self.peek().kind, TokenKind::PunctSemi) { return Err("Expected ;".to_string()); }
        self.advance();
        let update = if self.is_eof() {
            return Err("Unexpected EOF in for".to_string());
        } else if matches!(self.peek().kind, TokenKind::PunctRParen) {
            None
        } else { Some(self.parse_expr()?) };
        if self.is_eof() || !matches!(self.peek().kind, TokenKind::PunctRParen) { return Err("Expected )".to_string()); }
        self.advance();
        let body = self.parse_block_body()?;
        Ok(Stmt::For { init, condition, update, body })
    }

    fn parse_return(&mut self) -> Result<Stmt, String> {
        self.advance();
        let value = if self.is_eof() || matches!(self.peek().kind, TokenKind::PunctSemi) {
            None
        } else { Some(self.parse_expr()?) };
        if !self.is_eof() && matches!(self.peek().kind, TokenKind::PunctSemi) {
            self.advance();
        }
        Ok(Stmt::Return(value))
    }

    fn parse_try(&mut self) -> Result<Stmt, String> {
        self.advance();
        let body = self.parse_block_body()?;
        let mut catch_param = None;
        let mut catch_body = None;
        if matches!(self.peek().kind, TokenKind::KwCatch) {
            self.advance();
            if matches!(self.peek().kind, TokenKind::PunctLParen) {
                self.advance();
                catch_param = Some(self.expect_identifier()?);
                self.advance();
            }
            catch_body = Some(self.parse_block_body()?);
        }
        let mut finally = None;
        if matches!(self.peek().kind, TokenKind::KwFinally) {
            self.advance();
            finally = Some(self.parse_block_body()?);
        }
        Ok(Stmt::Try { body, catch_param, catch_body, finally })
    }

    fn parse_throw(&mut self) -> Result<Stmt, String> {
        self.advance();
        let expr = self.parse_expr()?;
        Ok(Stmt::Throw(expr))
    }

    fn parse_expr(&mut self) -> Result<Expr, String> { self.parse_assignment() }

    fn parse_assignment(&mut self) -> Result<Expr, String> {
        let left = self.parse_ternary()?;
        if matches!(self.peek().kind, TokenKind::OpAssign) {
            self.advance();
            let value = self.parse_assignment()?;
            return Ok(Expr::Assign { target: Box::new(left), value: Box::new(value) });
        }
        Ok(left)
    }

    fn parse_ternary(&mut self) -> Result<Expr, String> {
        let condition = self.parse_or()?;
        if matches!(self.peek().kind, TokenKind::PunctQuestion) {
            self.advance();
            let _then_branch = self.parse_assignment()?;
            if !matches!(self.peek().kind, TokenKind::PunctColon) { return Err("Expected :".to_string()); }
            self.advance();
            let else_branch = self.parse_assignment()?;
            return Ok(Expr::Binary {
                op: BinaryOp::And,
                left: Box::new(condition),
                right: Box::new(else_branch),
            });
        }
        Ok(condition)
    }

    fn parse_or(&mut self) -> Result<Expr, String> {
        let mut left = self.parse_and()?;
        while !self.is_eof() && matches!(self.peek().kind, TokenKind::OpOr) {
            self.advance();
            let right = self.parse_and()?;
            left = Expr::Binary { op: BinaryOp::Or, left: Box::new(left), right: Box::new(right) };
        }
        Ok(left)
    }

    fn parse_and(&mut self) -> Result<Expr, String> {
        let mut left = self.parse_equality()?;
        while !self.is_eof() && matches!(self.peek().kind, TokenKind::OpAnd) {
            self.advance();
            let right = self.parse_equality()?;
            left = Expr::Binary { op: BinaryOp::And, left: Box::new(left), right: Box::new(right) };
        }
        Ok(left)
    }

    fn parse_equality(&mut self) -> Result<Expr, String> {
        let mut left = self.parse_relational()?;
        loop {
            let op = match self.peek().kind {
                TokenKind::OpEq => Some(BinaryOp::Eq),
                TokenKind::OpStrictEq => Some(BinaryOp::StrictEq),
                TokenKind::OpNotEq => Some(BinaryOp::Ne),
                TokenKind::OpStrictNotEq => Some(BinaryOp::StrictNe),
                _ => None,
            };
            if let Some(op) = op {
                self.advance();
                let right = self.parse_relational()?;
                left = Expr::Binary { op, left: Box::new(left), right: Box::new(right) };
            } else { break; }
        }
        Ok(left)
    }

    fn parse_relational(&mut self) -> Result<Expr, String> {
        let mut left = self.parse_additive()?;
        loop {
            let op = match self.peek().kind {
                TokenKind::OpLt => Some(BinaryOp::Lt),
                TokenKind::OpGt => Some(BinaryOp::Gt),
                TokenKind::OpLtEq => Some(BinaryOp::LtEq),
                TokenKind::OpGtEq => Some(BinaryOp::GtEq),
                _ => None,
            };
            if let Some(op) = op {
                self.advance();
                let right = self.parse_additive()?;
                left = Expr::Binary { op, left: Box::new(left), right: Box::new(right) };
            } else { break; }
        }
        Ok(left)
    }

    fn parse_additive(&mut self) -> Result<Expr, String> {
        let mut left = self.parse_multiplicative()?;
        while !self.is_eof() && matches!(self.peek().kind, TokenKind::OpAdd | TokenKind::OpSub) {
            let op = match self.peek().kind {
                TokenKind::OpAdd => BinaryOp::Add,
                _ => BinaryOp::Sub,
            };
            self.advance();
            let right = self.parse_multiplicative()?;
            left = Expr::Binary { op, left: Box::new(left), right: Box::new(right) };
        }
        Ok(left)
    }

    fn parse_multiplicative(&mut self) -> Result<Expr, String> {
        let mut left = self.parse_unary()?;
        while !self.is_eof() && matches!(self.peek().kind, TokenKind::OpMul | TokenKind::OpDiv | TokenKind::OpMod) {
            let op = match self.peek().kind {
                TokenKind::OpMul => BinaryOp::Mul,
                TokenKind::OpDiv => BinaryOp::Div,
                _ => BinaryOp::Mod,
            };
            self.advance();
            let right = self.parse_unary()?;
            left = Expr::Binary { op, left: Box::new(left), right: Box::new(right) };
        }
        Ok(left)
    }

    fn parse_unary(&mut self) -> Result<Expr, String> {
        match self.peek().kind {
            TokenKind::OpSub => {
                self.advance();
                let operand = self.parse_unary()?;
                Ok(Expr::Unary { op: UnaryOp::Neg, operand: Box::new(operand) })
            }
            TokenKind::OpNot => {
                self.advance();
                let operand = self.parse_unary()?;
                Ok(Expr::Unary { op: UnaryOp::Not, operand: Box::new(operand) })
            }
            TokenKind::OpBitNot => {
                self.advance();
                let operand = self.parse_unary()?;
                Ok(Expr::Unary { op: UnaryOp::BitNot, operand: Box::new(operand) })
            }
            TokenKind::KwTypeof => {
                self.advance();
                let operand = self.parse_unary()?;
                Ok(Expr::Unary { op: UnaryOp::TypeOf, operand: Box::new(operand) })
            }
            TokenKind::KwVoid => {
                self.advance();
                let operand = self.parse_unary()?;
                Ok(Expr::Unary { op: UnaryOp::Void, operand: Box::new(operand) })
            }
            TokenKind::KwNew => {
                self.advance();
                let callee = self.parse_postfix()?;
                Ok(Expr::New(Box::new(callee)))
            }
            _ => self.parse_postfix(),
        }
    }

    fn parse_postfix(&mut self) -> Result<Expr, String> {
        let mut expr = self.parse_primary()?;
        loop {
            if self.is_eof() { break; }
            match self.peek().kind {
                TokenKind::PunctDot => {
                    self.advance();
                    let prop = self.expect_identifier()?;
                    expr = Expr::Member { object: Box::new(expr), property: prop, computed: false };
                }
                TokenKind::PunctLBracket => {
                    self.advance();
                    if self.is_eof() { return Err("Unexpected EOF in [".to_string()); }
                    let _prop_expr = self.parse_expr()?;
                    if self.is_eof() || !matches!(self.peek().kind, TokenKind::PunctRBracket) { return Err("Expected ]".to_string()); }
                    self.advance();
                    let prop_str = String::from("[computed]");
                    expr = Expr::Member { object: Box::new(expr), property: prop_str, computed: true };
                }
                TokenKind::PunctLParen => {
                    self.advance();
                    let mut args = Vec::new();
                    while !self.is_eof() && !matches!(self.peek().kind, TokenKind::PunctRParen) {
                        args.push(self.parse_expr()?);
                        if !self.is_eof() && matches!(self.peek().kind, TokenKind::PunctComma) { self.advance(); }
                    }
                    if self.is_eof() { return Err("Expected )".to_string()); }
                    self.advance();
                    expr = Expr::Call { callee: Box::new(expr), args };
                }
                _ => break,
            }
        }
        Ok(expr)
    }

    fn parse_primary(&mut self) -> Result<Expr, String> {
        let token = self.peek().clone();
        match token.kind {
            TokenKind::Number => {
                self.advance();
                let n: f64 = token.value.parse().unwrap_or(0.0);
                Ok(Expr::Number(n))
            }
            TokenKind::String => {
                self.advance();
                let s = token.value[1..token.value.len()-1].to_string();
                Ok(Expr::String(s))
            }
            TokenKind::Template => {
                self.advance();
                Ok(Expr::String(token.value))
            }
            TokenKind::KwTrue => { self.advance(); Ok(Expr::Bool(true)) }
            TokenKind::KwFalse => { self.advance(); Ok(Expr::Bool(false)) }
            TokenKind::KwNull => { self.advance(); Ok(Expr::Null) }
            TokenKind::KwUndefined => { self.advance(); Ok(Expr::Undefined) }
            TokenKind::KwThis => { self.advance(); Ok(Expr::This) }
            TokenKind::Identifier => {
                self.advance();
                Ok(Expr::Identifier(token.value))
            }
            TokenKind::PunctLParen => {
                self.advance();
                let expr = self.parse_expr()?;
                if self.is_eof() || !matches!(self.peek().kind, TokenKind::PunctRParen) { return Err("Expected )".to_string()); }
                self.advance();
                Ok(expr)
            }
            TokenKind::PunctLBracket => {
                self.advance();
                let mut elements = Vec::new();
                while !self.is_eof() && !matches!(self.peek().kind, TokenKind::PunctRBracket) {
                    elements.push(self.parse_expr()?);
                    if !self.is_eof() && matches!(self.peek().kind, TokenKind::PunctComma) { self.advance(); }
                }
                if self.is_eof() { return Err("Expected ]".to_string()); }
                self.advance();
                Ok(Expr::Array(elements))
            }
            TokenKind::PunctLBrace => {
                self.advance();
                let mut pairs = Vec::new();
                while !self.is_eof() && !matches!(self.peek().kind, TokenKind::PunctRBrace) {
                    let key = if let TokenKind::String = self.peek().kind {
                        let s = self.peek().value.clone();
                        self.advance();
                        if matches!(self.peek().kind, TokenKind::PunctColon) { self.advance(); }
                        s[1..s.len()-1].to_string()
                    } else if let TokenKind::Identifier = self.peek().kind {
                        let s = self.peek().value.clone();
                        self.advance();
                        if matches!(self.peek().kind, TokenKind::PunctColon) { self.advance(); }
                        s
                    } else {
                        return Err("Expected key".to_string());
                    };
                    let value = self.parse_expr()?;
                    pairs.push((key, value));
                    if matches!(self.peek().kind, TokenKind::PunctComma) { self.advance(); }
                }
                if self.is_eof() { return Err("Expected }".to_string()); }
                self.advance();
                Ok(Expr::Object(pairs))
            }
            TokenKind::Eof => Err("Unexpected end of input".to_string()),
            _ => Err(format!("Unexpected token: {:?}", token.kind)),
        }
    }

    fn peek(&self) -> &Token {
        if self.pos >= self.tokens.len() {
            // Return Eof token by referencing a static empty string
            const EOF_VALUE: &str = "";
            static EOF: std::sync::OnceLock<Token> = std::sync::OnceLock::new();
            EOF.get_or_init(|| Token {
                kind: TokenKind::Eof,
                value: EOF_VALUE.to_string(),
                line: 0,
                col: 0,
            })
        } else {
            &self.tokens[self.pos]
        }
    }
    fn advance(&mut self) { if self.pos < self.tokens.len() { self.pos += 1; } }
    fn is_eof(&self) -> bool {
        if self.pos >= self.tokens.len() {
            true
        } else {
            matches!(self.tokens[self.pos].kind, TokenKind::Eof)
        }
    }
    fn expect_identifier(&mut self) -> Result<String, String> {
        let token = self.peek().clone();
        if matches!(token.kind, TokenKind::Identifier) {
            self.advance();
            Ok(token.value)
        } else {
            Err(format!("Expected identifier, got {:?}", token.kind))
        }
    }
}
